import{_ as r,o as a,c as o,a4 as d}from"./chunks/framework.ChErgFjV.js";const b=JSON.parse('{"title":"初三数学知识体系","description":"","frontmatter":{"title":"初三数学知识体系","date":"2026-07-03T00:00:00.000Z","tags":["初中数学","九年级","广州中考"]},"headers":[],"relativePath":"study/junior-math/grade9.md","filePath":"study/junior-math/grade9.md","lastUpdated":1783652711000}'),l={name:"study/junior-math/grade9.md"};function e(n,t,i,h,s,g){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="初三数学知识体系-九年级" tabindex="-1">初三数学知识体系（九年级） <a class="header-anchor" href="#初三数学知识体系-九年级" aria-label="Permalink to &quot;初三数学知识体系（九年级）&quot;">​</a></h1><blockquote><p>🔴 <strong>中考高频</strong>　🟡 <strong>中考常考</strong>　🟢 <strong>基础掌握</strong></p><p>初三内容直接面向中考，二次函数、圆、相似三角形是广州中考的三大压轴板块。</p></blockquote><hr><h2 id="九年级上册" tabindex="-1">九年级上册 <a class="header-anchor" href="#九年级上册" aria-label="Permalink to &quot;九年级上册&quot;">​</a></h2><h3 id="第二十一章-一元二次方程-🔴" tabindex="-1">第二十一章 一元二次方程 🔴 <a class="header-anchor" href="#第二十一章-一元二次方程-🔴" aria-label="Permalink to &quot;第二十一章 一元二次方程 🔴&quot;">​</a></h3><blockquote><p>🔴 <strong>中考高频</strong>：一元二次方程是代数核心，必考知识点。</p></blockquote><h4 id="_21-1-一元二次方程" tabindex="-1">21.1 一元二次方程 <a class="header-anchor" href="#_21-1-一元二次方程" aria-label="Permalink to &quot;21.1 一元二次方程&quot;">​</a></h4><p><strong>知识点</strong>：标准形式 ax² + bx + c = 0（a≠0）。</p><h4 id="_21-2-解一元二次方程-🔴" tabindex="-1">21.2 解一元二次方程 🔴 <a class="header-anchor" href="#_21-2-解一元二次方程-🔴" aria-label="Permalink to &quot;21.2 解一元二次方程 🔴&quot;">​</a></h4><table tabindex="0"><thead><tr><th>方法</th><th>适用场景</th><th>案例</th></tr></thead><tbody><tr><td>直接开平方法</td><td>(x+a)² = b 形式</td><td>(x-1)² = 9 → x = 4 或 -2</td></tr><tr><td>因式分解法</td><td>方程易分解</td><td>x²-5x+6=0 → (x-2)(x-3)=0 → x=2 或 3</td></tr><tr><td>配方法</td><td>通用方法</td><td>x²+4x-1=0 → (x+2)²=5 → x=-2±√5</td></tr><tr><td>公式法</td><td>通用方法</td><td>x = (-b±√(b²-4ac))/(2a)</td></tr></tbody></table><p><strong>案例</strong>：</p><ul><li>2x² - 5x - 3 = 0 <ul><li>Δ = 25 + 24 = 49 &gt; 0</li><li>x = (5±7)/4 → x₁ = <strong>3</strong>，x₂ = <strong>-1/2</strong></li></ul></li></ul><h4 id="_21-3-根的判别式-🔴" tabindex="-1">21.3 根的判别式 🔴 <a class="header-anchor" href="#_21-3-根的判别式-🔴" aria-label="Permalink to &quot;21.3 根的判别式 🔴&quot;">​</a></h4><p><strong>知识点</strong>：Δ = b²-4ac</p><table tabindex="0"><thead><tr><th>Δ 值</th><th>根的情况</th></tr></thead><tbody><tr><td>Δ &gt; 0</td><td>两个不相等的实数根</td></tr><tr><td>Δ = 0</td><td>两个相等的实数根</td></tr><tr><td>Δ &lt; 0</td><td>无实数根</td></tr></tbody></table><p><strong>案例</strong>：</p><ul><li>方程 x² - 2x + k = 0 有两个不相等的实数根，求 k 的范围 <ul><li>Δ = 4 - 4k &gt; 0 → k &lt; <strong>1</strong></li></ul></li></ul><blockquote><p>⚠️ <strong>中考重点</strong>：根的判别式常与二次函数结合出题。</p></blockquote><h4 id="_21-4-实际问题与一元二次方程-🔴" tabindex="-1">21.4 实际问题与一元二次方程 🔴 <a class="header-anchor" href="#_21-4-实际问题与一元二次方程-🔴" aria-label="Permalink to &quot;21.4 实际问题与一元二次方程 🔴&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>某商品原价 100 元，连续两次降价的百分率相同，降后价 81 元，求每次降价的百分率 <ul><li>100(1-x)² = 81 → (1-x)² = 0.81 → 1-x = 0.9 → x = <strong>10%</strong></li></ul></li></ul><hr><h3 id="第二十二章-二次函数-🔴🔴🔴" tabindex="-1">第二十二章 二次函数 🔴🔴🔴 <a class="header-anchor" href="#第二十二章-二次函数-🔴🔴🔴" aria-label="Permalink to &quot;第二十二章 二次函数 🔴🔴🔴&quot;">​</a></h3><blockquote><p>🔴🔴🔴 <strong>中考最核心</strong>：二次函数是广州中考压轴题的首选载体，每年必考，分值 10-14 分。</p></blockquote><h4 id="_22-1-二次函数的图像和性质-🔴🔴" tabindex="-1">22.1 二次函数的图像和性质 🔴🔴 <a class="header-anchor" href="#_22-1-二次函数的图像和性质-🔴🔴" aria-label="Permalink to &quot;22.1 二次函数的图像和性质 🔴🔴&quot;">​</a></h4><p><strong>知识点</strong>：y = ax² + bx + c（a≠0）</p><table tabindex="0"><thead><tr><th>参数</th><th>作用</th></tr></thead><tbody><tr><td>a</td><td>a&gt;0 开口向上，a&lt;0 开口向下；</td></tr><tr><td>对称轴</td><td>x = -b/(2a)</td></tr><tr><td>顶点</td><td>(-b/(2a), (4ac-b²)/(4a))</td></tr><tr><td>c</td><td>与 y 轴交点纵坐标</td></tr></tbody></table><p><strong>顶点式</strong>：y = a(x-h)² + k，顶点 (h, k)</p><p><strong>案例</strong>：</p><ul><li>y = x² - 4x + 3 <ul><li>配方：y = (x-2)² - 1</li><li>开口<strong>向上</strong>，对称轴 x = <strong>2</strong>，顶点 <strong>(2, -1)</strong></li><li>与 x 轴交点：令 y=0 → (x-2)² = 1 → x = 1 或 3 → <strong>(1,0) 和 (3,0)</strong></li><li>与 y 轴交点：<strong>c = 3 → (0, 3)</strong></li></ul></li></ul><h4 id="_22-2-用函数观点看一元二次方程-🔴" tabindex="-1">22.2 用函数观点看一元二次方程 🔴 <a class="header-anchor" href="#_22-2-用函数观点看一元二次方程-🔴" aria-label="Permalink to &quot;22.2 用函数观点看一元二次方程 🔴&quot;">​</a></h4><p><strong>知识点</strong>：二次函数图像与 x 轴的交点 ↔ 一元二次方程的实数根。</p><table tabindex="0"><thead><tr><th>交点情况</th><th>Δ 值</th></tr></thead><tbody><tr><td>两个交点</td><td>Δ &gt; 0</td></tr><tr><td>一个交点（相切）</td><td>Δ = 0</td></tr><tr><td>无交点</td><td>Δ &lt; 0</td></tr></tbody></table><h4 id="_22-3-实际问题与二次函数-🔴🔴" tabindex="-1">22.3 实际问题与二次函数 🔴🔴 <a class="header-anchor" href="#_22-3-实际问题与二次函数-🔴🔴" aria-label="Permalink to &quot;22.3 实际问题与二次函数 🔴🔴&quot;">​</a></h4><blockquote><p>🔴🔴 <strong>压轴题标配</strong>：利润最大化、面积最大化、抛物线形实际问题。</p></blockquote><p><strong>案例 1（利润最大化）</strong>：</p><ul><li>某商品进价 30 元，售价 50 元时每天可卖 100 件，售价每提高 1 元少卖 2 件。求最大利润。 <ul><li>设提价 x 元，利润 y = (50+x-30)(100-2x) = (20+x)(100-2x)</li><li>= -2x² + 60x + 2000</li><li>对称轴 x = 60/4 = 15</li><li>最大利润 = (20+15)×(100-30) = 35×70 = <strong>2450 元</strong>，售价 <strong>65 元</strong></li></ul></li></ul><p><strong>案例 2（面积最大化）</strong>：</p><ul><li>用 40 米围栏靠墙围一个矩形场地，求最大面积。 <ul><li>设宽 x 米，长 = 40-2x，面积 S = x(40-2x) = -2x² + 40x</li><li>对称轴 x = 10，最大面积 = 10×20 = <strong>200 m²</strong></li></ul></li></ul><p><strong>案例 3（抛物线形问题）</strong> 🔴🔴：</p><ul><li>某涵洞截面为抛物线形，水面宽 4 米时水面距顶 2 米，求水面宽 6 米时水面距顶多少？ <ul><li>建系：顶点(0,0)，水面过(-2,-2)和(2,-2)</li><li>y = ax²，代入 -2 = 4a → a = -1/2 → y = -x²/2</li><li>水面宽 6 米 → x=3，y = -9/2 = -4.5 → 距顶 <strong>4.5 米</strong></li></ul></li></ul><hr><h3 id="第二十三章-旋转-🟡" tabindex="-1">第二十三章 旋转 🟡 <a class="header-anchor" href="#第二十三章-旋转-🟡" aria-label="Permalink to &quot;第二十三章 旋转 🟡&quot;">​</a></h3><h4 id="_23-1-图形的旋转" tabindex="-1">23.1 图形的旋转 <a class="header-anchor" href="#_23-1-图形的旋转" aria-label="Permalink to &quot;23.1 图形的旋转&quot;">​</a></h4><p><strong>知识点</strong>：旋转中心、旋转角、旋转方向；旋转前后图形全等。</p><h4 id="_23-2-中心对称-🟡" tabindex="-1">23.2 中心对称 🟡 <a class="header-anchor" href="#_23-2-中心对称-🟡" aria-label="Permalink to &quot;23.2 中心对称 🟡&quot;">​</a></h4><p><strong>知识点</strong>：中心对称图形（如平行四边形、圆）；关于原点对称的坐标关系。</p><p><strong>案例</strong>：</p><ul><li>点 P(2, -3) 关于原点对称点 → <strong>(-2, 3)</strong></li></ul><blockquote><p>💡 <strong>中考提示</strong>：旋转常与全等三角形、特殊平行四边形结合出综合题。</p></blockquote><hr><h3 id="第二十四章-圆-🔴🔴" tabindex="-1">第二十四章 圆 🔴🔴 <a class="header-anchor" href="#第二十四章-圆-🔴🔴" aria-label="Permalink to &quot;第二十四章 圆 🔴🔴&quot;">​</a></h3><blockquote><p>🔴🔴 <strong>中考核心</strong>：圆是广州中考几何部分的重点，每年出 1-2 道大题。</p></blockquote><h4 id="_24-1-圆的有关性质-🔴" tabindex="-1">24.1 圆的有关性质 🔴 <a class="header-anchor" href="#_24-1-圆的有关性质-🔴" aria-label="Permalink to &quot;24.1 圆的有关性质 🔴&quot;">​</a></h4><p><strong>知识点</strong>：垂径定理；弧、弦、圆心角的关系；圆周角定理。</p><p><strong>垂径定理</strong>：垂直于弦的直径平分弦及所对的两条弧。</p><p><strong>圆周角定理</strong>：同弧上的圆周角是圆心角的一半。</p><p><strong>案例</strong>：</p><ul><li>⊙O 中弦 AB = 8，圆心到弦的距离 d = 3，则半径 r = √(16+9) = <strong>5</strong></li><li>圆心角 ∠AOB = 80°，则圆周角 ∠ACB = <strong>40°</strong>（同弧）</li><li>半圆（直径）所对的圆周角 = <strong>90°</strong></li></ul><h4 id="_24-2-点和圆的位置关系-🟡" tabindex="-1">24.2 点和圆的位置关系 🟡 <a class="header-anchor" href="#_24-2-点和圆的位置关系-🟡" aria-label="Permalink to &quot;24.2 点和圆的位置关系 🟡&quot;">​</a></h4><p><strong>知识点</strong>：d &lt; r → 在圆内；d = r → 在圆上；d &gt; r → 在圆外。</p><p><strong>三角形的外心</strong>：三边垂直平分线交点，到三个顶点距离相等。</p><h4 id="_24-3-直线和圆的位置关系-🔴" tabindex="-1">24.3 直线和圆的位置关系 🔴 <a class="header-anchor" href="#_24-3-直线和圆的位置关系-🔴" aria-label="Permalink to &quot;24.3 直线和圆的位置关系 🔴&quot;">​</a></h4><table tabindex="0"><thead><tr><th>位置关系</th><th>d 与 r 的关系</th><th>交点数</th></tr></thead><tbody><tr><td>相离</td><td>d &gt; r</td><td>0</td></tr><tr><td>相切</td><td>d = r</td><td>1</td></tr><tr><td>相交</td><td>d &lt; r</td><td>2</td></tr></tbody></table><p><strong>切线定理</strong> 🔴：切线垂直于过切点的半径。</p><p><strong>切线长定理</strong> 🟡：从圆外一点引圆的两条切线，切线长相等。</p><p><strong>案例</strong>：</p><ul><li>⊙O 半径为 3，圆心 O 到直线 l 的距离为 5，则直线与圆 <strong>相离</strong></li><li>PA、PB 切⊙O 于 A、B，PA = 5，则 PB = <strong>5</strong></li></ul><h4 id="_24-4-弧长和扇形面积-🟡" tabindex="-1">24.4 弧长和扇形面积 🟡 <a class="header-anchor" href="#_24-4-弧长和扇形面积-🟡" aria-label="Permalink to &quot;24.4 弧长和扇形面积 🟡&quot;">​</a></h4><p><strong>公式</strong>：</p><ul><li>弧长 l = nπr/180</li><li>扇形面积 S = nπr²/360 = lr/2</li></ul><p><strong>案例</strong>：</p><ul><li>半径 6，圆心角 120° 的弧长 = 120×π×6/180 = <strong>4π</strong></li><li>对应扇形面积 = 120×π×36/360 = <strong>12π</strong></li></ul><h4 id="_24-5-圆锥-🟢" tabindex="-1">24.5 圆锥 🟢 <a class="header-anchor" href="#_24-5-圆锥-🟢" aria-label="Permalink to &quot;24.5 圆锥 🟢&quot;">​</a></h4><p><strong>知识点</strong>：侧面积 = πrl（r 底面半径，l 母线长）。</p><hr><h2 id="九年级下册" tabindex="-1">九年级下册 <a class="header-anchor" href="#九年级下册" aria-label="Permalink to &quot;九年级下册&quot;">​</a></h2><h3 id="第二十五章-概率初步-🟡" tabindex="-1">第二十五章 概率初步 🟡 <a class="header-anchor" href="#第二十五章-概率初步-🟡" aria-label="Permalink to &quot;第二十五章 概率初步 🟡&quot;">​</a></h3><h4 id="_25-1-随机事件与概率" tabindex="-1">25.1 随机事件与概率 <a class="header-anchor" href="#_25-1-随机事件与概率" aria-label="Permalink to &quot;25.1 随机事件与概率&quot;">​</a></h4><p><strong>知识点</strong>：必然事件（P=1）、不可能事件（P=0）、随机事件（0&lt;P&lt;1）。</p><h4 id="_25-2-用列举法求概率-🟡" tabindex="-1">25.2 用列举法求概率 🟡 <a class="header-anchor" href="#_25-2-用列举法求概率-🟡" aria-label="Permalink to &quot;25.2 用列举法求概率 🟡&quot;">​</a></h4><p><strong>知识点</strong>：列表法、树形图法。</p><p><strong>案例</strong>：</p><ul><li>掷两枚硬币，一正一反的概率？ <ul><li>(正,正), (正,反), (反,正), (反,反) → P = <strong>2/4 = 1/2</strong></li></ul></li><li>口袋中有 3 红 2 白共 5 个球，摸出 2 个球恰好一红一白的概率？ <ul><li>C(3,1)×C(2,1) / C(5,2) = 6/10 = <strong>3/5</strong></li></ul></li></ul><h4 id="_25-3-用频率估计概率-🟢" tabindex="-1">25.3 用频率估计概率 🟢 <a class="header-anchor" href="#_25-3-用频率估计概率-🟢" aria-label="Permalink to &quot;25.3 用频率估计概率 🟢&quot;">​</a></h4><blockquote><p>💡 <strong>中考提示</strong>：概率题一般出一道选择/填空（3分），难度不大。</p></blockquote><hr><h3 id="第二十六章-反比例函数-🔴" tabindex="-1">第二十六章 反比例函数 🔴 <a class="header-anchor" href="#第二十六章-反比例函数-🔴" aria-label="Permalink to &quot;第二十六章 反比例函数 🔴&quot;">​</a></h3><blockquote><p>🔴 <strong>中考高频</strong>：反比例函数常与一次函数结合出综合题。</p></blockquote><h4 id="_26-1-反比例函数-🟡" tabindex="-1">26.1 反比例函数 🟡 <a class="header-anchor" href="#_26-1-反比例函数-🟡" aria-label="Permalink to &quot;26.1 反比例函数 🟡&quot;">​</a></h4><p><strong>知识点</strong>：y = k/x（k≠0），图像为双曲线。</p><table tabindex="0"><thead><tr><th>k 值</th><th>图像位置</th><th>增减性</th></tr></thead><tbody><tr><td>k &gt; 0</td><td>一、三象限</td><td>每个象限内 y 随 x 增大而减小</td></tr><tr><td>k &lt; 0</td><td>二、四象限</td><td>每个象限内 y 随 x 增大而增大</td></tr></tbody></table><p><strong>案例</strong>：</p><ul><li>y = 6/x 过点 (2, ? ) → y = 3，过点 (3, ? ) → y = 2</li><li>|k| 的几何意义：双曲线上任一点与坐标轴围成矩形面积 = <strong>|k|</strong></li></ul><h4 id="_26-2-实际问题与反比例函数-🟡" tabindex="-1">26.2 实际问题与反比例函数 🟡 <a class="header-anchor" href="#_26-2-实际问题与反比例函数-🟡" aria-label="Permalink to &quot;26.2 实际问题与反比例函数 🟡&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>电压 U = 220V 不变，电流 I 与电阻 R 成反比：I = 220/R</li><li>R = 44Ω 时 I = <strong>5A</strong>；I = 2A 时 R = <strong>110Ω</strong></li></ul><hr><h3 id="第二十七章-相似-🔴🔴" tabindex="-1">第二十七章 相似 🔴🔴 <a class="header-anchor" href="#第二十七章-相似-🔴🔴" aria-label="Permalink to &quot;第二十七章 相似 🔴🔴&quot;">​</a></h3><blockquote><p>🔴🔴 <strong>中考核心</strong>：相似三角形是广州中考几何压轴题的重要工具。</p></blockquote><h4 id="_27-1-图形的相似" tabindex="-1">27.1 图形的相似 <a class="header-anchor" href="#_27-1-图形的相似" aria-label="Permalink to &quot;27.1 图形的相似&quot;">​</a></h4><h4 id="_27-2-相似三角形-🔴🔴" tabindex="-1">27.2 相似三角形 🔴🔴 <a class="header-anchor" href="#_27-2-相似三角形-🔴🔴" aria-label="Permalink to &quot;27.2 相似三角形 🔴🔴&quot;">​</a></h4><p><strong>判定方法</strong>：</p><table tabindex="0"><thead><tr><th>方法</th><th>条件</th></tr></thead><tbody><tr><td>AA</td><td>两角对应相等</td></tr><tr><td>SAS</td><td>两边成比例且夹角相等</td></tr><tr><td>SSS</td><td>三边成比例</td></tr></tbody></table><p><strong>性质</strong>：</p><ul><li>对应边成比例、对应角相等</li><li>面积比 = 相似比的平方</li><li>周长比 = 相似比</li></ul><p><strong>案例</strong>：</p><ul><li>△ABC ∼ △DEF，相似比 2:3，S△ABC = 12，则 S△DEF = 12 × (3/2)² = <strong>27</strong></li></ul><h4 id="_27-3-位似-🟢" tabindex="-1">27.3 位似 🟢 <a class="header-anchor" href="#_27-3-位似-🟢" aria-label="Permalink to &quot;27.3 位似 🟢&quot;">​</a></h4><p><strong>知识点</strong>：位似图形是特殊的相似图形，对应点连线交于位似中心。</p><blockquote><p>⚠️ <strong>中考压轴常考</strong>：相似三角形与二次函数、圆的结合。广州近 3 年压轴题至少 1 道涉及相似。</p></blockquote><hr><h3 id="第二十八章-锐角三角函数-🔴" tabindex="-1">第二十八章 锐角三角函数 🔴 <a class="header-anchor" href="#第二十八章-锐角三角函数-🔴" aria-label="Permalink to &quot;第二十八章 锐角三角函数 🔴&quot;">​</a></h3><blockquote><p>🔴 <strong>中考高频</strong>：解直角三角形是必考内容，常出现在应用题中。</p></blockquote><h4 id="_28-1-锐角三角函数-🔴" tabindex="-1">28.1 锐角三角函数 🔴 <a class="header-anchor" href="#_28-1-锐角三角函数-🔴" aria-label="Permalink to &quot;28.1 锐角三角函数 🔴&quot;">​</a></h4><table tabindex="0"><thead><tr><th>函数</th><th>定义</th><th>特殊角 30°</th><th>特殊角 45°</th><th>特殊角 60°</th></tr></thead><tbody><tr><td>sin A</td><td>对边/斜边</td><td>1/2</td><td>√2/2</td><td>√3/2</td></tr><tr><td>cos A</td><td>邻边/斜边</td><td>√3/2</td><td>√2/2</td><td>1/2</td></tr><tr><td>tan A</td><td>对边/邻边</td><td>√3/3</td><td>1</td><td>√3</td></tr></tbody></table><blockquote><p>⚠️ <strong>必须记忆</strong>：30°、45°、60° 的三角函数值是中考必考。</p></blockquote><p><strong>案例</strong>：</p><ul><li>在 Rt△ABC 中，∠C=90°，AB=10，sinA=3/5，求 BC <ul><li>BC/AB = 3/5 → BC = <strong>6</strong>，AC = 8</li></ul></li></ul><h4 id="_28-2-解直角三角形-🔴" tabindex="-1">28.2 解直角三角形 🔴 <a class="header-anchor" href="#_28-2-解直角三角形-🔴" aria-label="Permalink to &quot;28.2 解直角三角形 🔴&quot;">​</a></h4><p><strong>知识点</strong>：已知两元素（至少一个边）可解直角三角形。</p><p><strong>案例</strong>：</p><ul><li>某人在山脚 A 处测得山顶 B 仰角 30°，沿 30° 坡面走 200 米到 C，再测山顶仰角 60°，求山高。 <ul><li>设山高 h，作辅助线后：</li><li>在△BCD 中，∠BCD = 30°，∠CBD = 30°</li><li>BD = BC = 200（等腰三角形判定）</li><li>h = BD × sin60° = 200 × √3/2 = <strong>100√3 ≈ 173.2 米</strong></li></ul></li></ul><h4 id="_28-3-实际问题与锐角三角函数-🔴" tabindex="-1">28.3 实际问题与锐角三角函数 🔴 <a class="header-anchor" href="#_28-3-实际问题与锐角三角函数-🔴" aria-label="Permalink to &quot;28.3 实际问题与锐角三角函数 🔴&quot;">​</a></h4><blockquote><p>常见应用场景：仰角/俯角问题、坡度/坡角问题、方向角问题、航海问题。</p></blockquote><hr><h3 id="第二十九章-投影与视图-🟢" tabindex="-1">第二十九章 投影与视图 🟢 <a class="header-anchor" href="#第二十九章-投影与视图-🟢" aria-label="Permalink to &quot;第二十九章 投影与视图 🟢&quot;">​</a></h3><h4 id="_29-1-投影" tabindex="-1">29.1 投影 <a class="header-anchor" href="#_29-1-投影" aria-label="Permalink to &quot;29.1 投影&quot;">​</a></h4><p><strong>知识点</strong>：平行投影、中心投影。</p><h4 id="_29-2-三视图-🟡" tabindex="-1">29.2 三视图 🟡 <a class="header-anchor" href="#_29-2-三视图-🟡" aria-label="Permalink to &quot;29.2 三视图 🟡&quot;">​</a></h4><p><strong>知识点</strong>：主视图、俯视图、左视图的画法；由三视图还原几何体。</p><p><strong>案例</strong>：</p><ul><li>由三视图还原：主视图为三角形，俯视图为圆，则该几何体为 <strong>圆锥</strong></li></ul><blockquote><p>💡 <strong>中考提示</strong>：三视图一般出一道选择题（3分），送分题。</p></blockquote><hr><h2 id="初三重点总结" tabindex="-1">初三重点总结 <a class="header-anchor" href="#初三重点总结" aria-label="Permalink to &quot;初三重点总结&quot;">​</a></h2><h3 id="广州中考初三相关考点权重" tabindex="-1">广州中考初三相关考点权重 <a class="header-anchor" href="#广州中考初三相关考点权重" aria-label="Permalink to &quot;广州中考初三相关考点权重&quot;">​</a></h3><table tabindex="0"><thead><tr><th>章节</th><th>中考占比</th><th>重要性</th><th>说明</th></tr></thead><tbody><tr><td>二次函数</td><td>约 12-15%</td><td>🔴🔴🔴</td><td>压轴题核心</td></tr><tr><td>圆</td><td>约 8-10%</td><td>🔴🔴</td><td>几何大题必出</td></tr><tr><td>相似三角形</td><td>约 6-8%</td><td>🔴🔴</td><td>压轴题常见</td></tr><tr><td>锐角三角函数</td><td>约 5-7%</td><td>🔴</td><td>应用题必出</td></tr><tr><td>一元二次方程</td><td>约 5-6%</td><td>🔴</td><td>代数基础</td></tr><tr><td>反比例函数</td><td>约 4-5%</td><td>🔴</td><td>常与一次函数结合</td></tr><tr><td>概率</td><td>约 3-4%</td><td>🟡</td><td>选择/填空</td></tr><tr><td>旋转</td><td>约 2-3%</td><td>🟡</td><td>结合全等考</td></tr><tr><td>三视图</td><td>约 2%</td><td>🟢</td><td>送分选择</td></tr></tbody></table><hr><h2 id="广州中考数学总览" tabindex="-1">广州中考数学总览 <a class="header-anchor" href="#广州中考数学总览" aria-label="Permalink to &quot;广州中考数学总览&quot;">​</a></h2><h3 id="全三年考点分值分布-满分-120-分" tabindex="-1">全三年考点分值分布（满分 120 分） <a class="header-anchor" href="#全三年考点分值分布-满分-120-分" aria-label="Permalink to &quot;全三年考点分值分布（满分 120 分）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>板块</th><th>分值</th><th>占比</th></tr></thead><tbody><tr><td>数与代数（方程、函数、不等式）</td><td>约 42-48 分</td><td>35-40%</td></tr><tr><td>图形与几何（三角形、四边形、圆、相似）</td><td>约 42-48 分</td><td>35-40%</td></tr><tr><td>统计与概率</td><td>约 12-15 分</td><td>10-12%</td></tr><tr><td>综合与实践（压轴题）</td><td>约 15-20 分</td><td>12-17%</td></tr></tbody></table><h3 id="广州中考压轴题规律-2022-2025" tabindex="-1">广州中考压轴题规律（2022-2025） <a class="header-anchor" href="#广州中考压轴题规律-2022-2025" aria-label="Permalink to &quot;广州中考压轴题规律（2022-2025）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>第 24 题</th><th>第 25 题</th></tr></thead><tbody><tr><td>2022</td><td>二次函数+面积最值</td><td>几何旋转+相似综合</td></tr><tr><td>2023</td><td>二次函数+线段最值</td><td>圆+相似+最值</td></tr><tr><td>2024</td><td>二次函数+动点问题</td><td>几何变换+相似综合</td></tr><tr><td>2025</td><td>二次函数+存在性问题</td><td>圆+三角函数综合</td></tr></tbody></table><p><strong>压轴题规律总结</strong>：</p><ol><li><strong>第 24 题几乎必考二次函数</strong> — 常见类型：面积最值、线段最值、动点存在性</li><li><strong>第 25 题考几何综合</strong> — 相似三角形 + 圆/旋转/最值</li><li><strong>动点问题年年有</strong> — 分类讨论思想是核心</li><li><strong>数形结合贯穿始终</strong> — 建系、解析法越来越受重视</li></ol><h3 id="备考策略" tabindex="-1">备考策略 <a class="header-anchor" href="#备考策略" aria-label="Permalink to &quot;备考策略&quot;">​</a></h3><ol><li><strong>二轮复习法</strong>：一轮按章节过（2月-4月），二轮按专题突破（4月-5月）</li><li><strong>压轴题训练</strong>：每天一道二次函数综合 + 一道几何综合</li><li><strong>计算零失误</strong>：有理数运算、解方程、因式分解必须快且准</li><li><strong>规范书写</strong>：几何证明格式、辅助线作法描述，广州阅卷非常看重规范性</li><li><strong>真题为王</strong>：近 5 年广州中考真题至少做 3 遍，理解出题思路比刷题量更重要</li></ol>',148)])])}const c=r(l,[["render",e]]);export{b as __pageData,c as default};
